func (s *service) CreatePlanAddon(ctx context.Context, params planaddon.CreatePlanAddonInput) (*planaddon.PlanAddon, error) {
    if err := params.Validate(); err != nil { return nil, err }
    // cross-entity checks: plan must be active, addon must be active
    return transaction.Run(ctx, s.adapter, func(ctx context.Context) (*planaddon.PlanAddon, error) {
        created, err := s.adapter.CreatePlanAddon(ctx, params)
        if err != nil { return nil, err }
        event := planaddon.NewPlanAddonCreateEvent(ctx, created)
        if err := s.publisher.Publish(ctx, event); err != nil {
            return nil, fmt.Errorf("publish planaddon created: %w", err)
        }
        return created, nil
    })
}

import (
    plansubscription "github.com/openmeterio/openmeter/openmeter/productcatalog/subscription"
)

func (s *service) Create(ctx context.Context, req plansubscription.CreateSubscriptionRequest) (*subscription.Subscription, error) {
    pi := req.PlanInput
    if ref := pi.AsRef(); ref != nil {
        fetchedPlan, err := s.getPlanByVersion(ctx, ns, ref.Key, ref.Version)
        if err != nil { return nil, err }
        adaptedPlan := &plansubscription.Plan{
            Plan: fetchedPlan.AsProductCatalogPlan(),
            Ref:  &models.NamespacedID{ID: fetchedPlan.ID},
        }
        if req.StartingPhase != nil {
            zeroPhasesBeforeStartingPhase(adaptedPlan, *req.StartingPhase)
        }
        return s.workflowService.CreateFromPlan(ctx, workflowInput, adaptedPlan)
    }
    // inline plan path
    return s.workflowService.CreateFromPlan(ctx, workflowInput, inlineAdaptedPlan)
}
